from Bio.Seq import Seq
s = Seq("".replace("\n", "").strip())
t = Seq("".replace("\n", "").strip())

#hammin distance = total number of point mutations occured
hamming_distance = sum(a != b for a, b in zip(s, t))
#sum we want count of point mutations not names
#in that if a not eqaul to b by creating for loop in a and b 
#zip is used when we want the result in pairs
print(hamming_distance)